// FIFO Page Replacement Algorithm
// frames: number of memory frames
// referenceString: sequence of page references

FUNCTION FIFO_PageFaults(frames, referenceString)
 SET frameList = EMPTY_QUEUE
 SET pageFaults = 0

 FOR page IN referenceString
 IF page NOT IN frameList THEN
 // Page fault occurs
 pageFaults = pageFaults + 1

 IF frameList.size() < frames THEN
 // Empty frame available
 ENQUEUE(frameList, page)
 ELSE
 // Remove oldest page (front)
 DEQUEUE(frameList)
 // Add new page at rear
 ENQUEUE(frameList, page)
 END IF
 END IF
 END FOR

 RETURN pageFaults
END FUNCTION

// Example usage:
// faults = FIFO_PageFaults(3, [1,2,3,4,1,2,5,1,2])
// Expected: 7 page faults

// LRU Page Replacement Algorithm
// Uses counter to track page usage time

FUNCTION LRU_PageFaults(frames, referenceString)
 SET frameTable = EMPTY_ARRAY // stores (page, counter)
 SET counter = 0
 SET pageFaults = 0

 FOR page IN referenceString
 counter = counter + 1

 IF page IN frameTable THEN
 // Page hit - update counter
 frameTable[page].counter = counter
 ELSE
 // Page fault
 pageFaults = pageFaults + 1

 IF frameTable.size() < frames THEN
 // Add to available frame
 frameTable[page] = counter
 ELSE
 // Find LRU page (minimum counter)
 victimPage = frameTable with minimum counter
 REMOVE(frameTable, victimPage)
 ADD(frameTable, page, counter)
 END IF
 END IF
 END FOR

 RETURN pageFaults
END FUNCTION

